package com.vycepay.admin.api.v1;
import java.util.*; import com.vycepay.admin.api.v1.dto.AdminRequests.AdminPasswordResetRequest; import com.vycepay.admin.api.v1.dto.AdminRequests.AdminUserCreateRequest; import com.vycepay.admin.api.v1.dto.AdminRequests.AdminUserUpdateRequest; import com.vycepay.admin.application.service.*; import com.vycepay.common.api.*; import jakarta.servlet.http.HttpServletRequest; import jakarta.validation.Valid; import org.springframework.http.ResponseEntity; import org.springframework.security.access.prepost.PreAuthorize; import org.springframework.web.bind.annotation.*;
/** Admin user management APIs. */
@RestController @RequestMapping("/api/admin/v1/users") @PreAuthorize("hasAuthority('PERM_admin:manage_users')")
public class AdminUserController{private final AdminReadService r; private final AdminMutationService m; private final RateLimitService rateLimitService; public AdminUserController(AdminReadService r,AdminMutationService m,RateLimitService rateLimitService){this.r=r;this.m=m;this.rateLimitService=rateLimitService;} @GetMapping public ResponseEntity<ApiSuccessResponse<Map<String,Object>>> list(@RequestParam(required=false)Integer page,@RequestParam(required=false)Integer size){return ResponseEntity.ok(ApiSuccessResponses.ok("ADMIN_USERS_OK","Admin users",r.adminUsers(page,size)));} @GetMapping("/{id}") public ResponseEntity<ApiSuccessResponse<Map<String,Object>>> detail(@PathVariable Long id){return ResponseEntity.ok(ApiSuccessResponses.ok("ADMIN_USER_OK","Admin user",r.adminUser(id)));} @PostMapping public ResponseEntity<ApiSuccessResponse<Map<String,Object>>> create(@Valid @RequestBody AdminUserCreateRequest body,HttpServletRequest req){rateLimitService.check("mutation",req);Long id=m.createAdminUser(body,req);return ResponseEntity.ok(ApiSuccessResponses.ok("ADMIN_USER_CREATED","Admin user created",Map.of("id",id)));} @PutMapping("/{id}") public ResponseEntity<ApiSuccessResponse<Void>> update(@PathVariable Long id,@Valid @RequestBody AdminUserUpdateRequest body,HttpServletRequest req){rateLimitService.check("mutation",req);m.updateAdminUser(id,body,req);return ResponseEntity.ok(ApiSuccessResponses.ok("ADMIN_USER_UPDATED","Admin user updated"));} @PostMapping("/{id}/reset-password") public ResponseEntity<ApiSuccessResponse<Void>> reset(@PathVariable Long id,@Valid @RequestBody AdminPasswordResetRequest body,HttpServletRequest req){rateLimitService.check("mutation",req);m.resetAdminPassword(id,body,req);return ResponseEntity.ok(ApiSuccessResponses.ok("ADMIN_USER_PASSWORD_RESET","Password reset"));}}
